blocks.body:
{
    "level": "A1–A2",
    "intro": "W tym temacie poznasz <strong>formy pytań</strong> (formy pytań) w języku angielskim – główne typy zdań pytających i zasady ich budowy.",
    "rules": [
        {
            "label": "TAK/NIE PYTANIA",
            "color": "emerald",
            "text": "<strong>Pytania ogólne</strong> - odpowiedz „tak” lub „nie”:",
            "example": "Czy lubisz herbatę? Czy jesteś gotowy? Czy możesz pomóc?"
        },
        {
            "label": "WH-PYTANIA",
            "color": "blue",
            "text": "<strong>Pytania specjalne</strong> — zacznij od słowa pytającego:",
            "example": "Czego chcesz? Gdzie idziesz? Dlaczego ona tu jest?"
        },
        {
            "label": "KOLEŃSTWO WYRAZÓW",
            "color": "amber",
            "text": "<strong>Inwersja</strong> to czasownik posiłkowy przed podmiotem:",
            "example": "Pomocniczy + Temat + Czasownik główny"
        }
    ]
}

{
    "title": "1. Co to są formularze pytań?",
    "intro": "Istnieją różne sposoby zadawania pytań w języku angielskim:",
    "items": [
        {
            "label": "Tak/Nie",
            "title": "Pytania ogólne",
            "subtitle": "Odpowiedź tak lub nie — Czy...? Czy ona...?"
        },
        {
            "label": "Jakie pytania",
            "title": "Pytania specjalne",
            "subtitle": "Zacznij od tego, co, gdzie, kiedy, dlaczego, kto, jak"
        },
        {
            "label": "Alternatywa",
            "title": "Alternatywa pytania",
            "subtitle": "Wybierz opcję — Kawa czy herbata?"
        },
        {
            "label": "Tag",
            "title": "Pytania do rozdziału",
            "subtitle": "Pytania na końcu zdania — Podoba Ci się, prawda?"
        },
        {
            "label": "Temat",
            "title": "Pytanie do tematu",
            "subtitle": "Kto/co jako temat — kto przyszedł? Co się stało?"
        },
        {
            "label": "Pośrednie",
            "title": "Pytania pośrednie",
            "subtitle": "Więcej grzecznych formularzy — Czy możesz mi powiedzieć, gdzie...?"
        }
    ]
}

{
    "title": "2. Podstawowa kolejność słów w pytaniach",
    "sections": [
        {
            "label": "Odwrócenie podmiotu i czasownika",
            "color": "emerald",
            "description": "W pytaniach <strong>czasownik pomocniczy jest umieszczany przed podmiotem</strong>. Nazywa się to inwersją.",
            "examples": [
                {
                    "en": "Jesteś gotowy. → Czy jesteś gotowy?",
                    "ua": "Czy jesteś gotowy? (inwersja jesteś i ty)"
                },
                {
                    "en": "Umie pływać. → Umie pływać?",
                    "ua": "Umie pływać? (odwrócenie puszki i ona)"
                },
                {
                    "en": "Przyjdą. → Czy przyjdą?",
                    "ua": " (odwrócenie woli i oni)"
                }
            ]
        },
        {
            "label": "Ogólna formuła pytania",
            "color": "blue",
            "description": "Podstawowa struktura pytania w języku angielskim:",
            "examples": [
                {
                    "en": "Pomocniczy + Temat + Czasownik główny + ...?",
                    "ua": "Pomocniczy + Podmiot + Czasownik główny + ...?"
                },
                {
                    "en": "Czy mówisz po angielsku?",
                    "ua": "Czy mówisz po angielsku?"
                },
                {
                    "en": "Czy on przyjdzie dziś wieczorem?",
                    "ua": "On przyjdzie dziś wieczorem?"
                }
            ],
            "note": "📌 Czasownik pomocniczy zawsze poprzedza podmiot w pytania!"
        }
    ]
}

{
    "title": "3. Pytania typu „tak/nie” — pytania ogólne",
    "sections": [
        {
            "label": "Z DO/DOES/DID",
            "color": "emerald",
            "description": "W czasach prostych (prostych) do tworzenia pytań używamy słowa <strong>do/does/did</strong>.",
            "examples": [
                {
                    "en": "Czy lubisz kawę?",
                    "ua": "Lubisz kawa?"
                },
                {
                    "en": "Czy ona tu pracuje?",
                    "ua": "Czy ona tu pracuje?"
                },
                {
                    "en": "Czy przybyli na czas?",
                    "ua": "Przybyli na czas?"
                }
            ]
        },
        {
            "label": "Z TO BE",
            "color": "sky",
            "description": "Z czasownikiem <strong>być</strong> dokonujemy inwersji – stawiamy być przed temat.",
            "examples": [
                {
                    "en": "Czy jesteś gotowy? <strong>Czasowniki modalne</strong> (can, will, must, may) dokonują inwersji.",
                    "ua": "Ти готовий?"
                },
                {
                    "en": "Is she at home?",
                    "ua": "Вона вдома?"
                },
                {
                    "en": "Were they happy?",
                    "ua": "Вони були щасливі?"
                }
            ]
        },
        {
            "label": "З модальними дієсловами",
            "color": "purple",
            "description": "З <strong>модальними дієсловами</strong> (can, will, should, must, may) робимо інверсію.",
            "examples": [
                {
                    "en": "Umiesz pływać?",
                    "ua": "Czy umiesz pływać?"
                },
                {
                    "en": "Czy ona przyjdzie?",
                    "ua": "Ona przyjdzie przyjdź?"
                },
                {
                    "en": "Czy powinniśmy poczekać?",
                    "ua": "Czy powinniśmy poczekać?"
                }
            ]
        }
    ]
}

{
    "title": "4. Wh-Pytania – pytania specjalne",
    "sections": [
        {
            "label": "Słowa pytań)",
            "color": "emerald",
            "description": "Pytania specjalne zaczynają się od <strong>słowa zapytania</strong>:",
            "examples": [
                {
                    "en": "Co? ",
                    "ua": "Czego chcesz? - Czego chcesz? "
                },
                {
                    "en": "Gdzie - Gdzie? Kudi?",
                    "ua": "Dokąd idziesz? - Dokąd idziesz?"
                },
                {
                    "en": "Kiedy - Koli?",
                    "ua": "Kiedy przyjechali? - Kiedy przyjechali?"
                },
                {
                    "en": "Dlaczego - Dlaczego?",
                    "ua": "Dlaczego ona płacze? - Dlaczego ona płacze?"
                },
                {
                    "en": "Kto - Kto?",
                    "ua": "Kto do ciebie dzwonił? - Kto do ciebie dzwonił?"
                },
                {
                    "en": "Jak - Jak?",
                    "ua": "Skąd wiesz? — Skąd wiesz?"
                }
            ]
        },
        {
            "label": "Struktura pytania Wh",
            "color": "blue",
            "description": "Formuła pytania specjalnego:",
            "examples": [
                {
                    "en": "Słowo-posiłkowe + podmiot + czasownik główny?",
                    "ua": "Słowo pytające + podmiot + czasownik?"
                },
                {
                    "en": "Czego chcesz?",
                    "ua": "Czego chcesz?[[[CODX_4]]]Dokąd ona idzie? ona odchodzi?"
                },
                {
                    "en": "Where is she going?",
                    "ua": "Куди вона йде?"
                },
                {
                    "en": "Dlaczego wyszli?",
                    "ua": "Dlaczego wyszli?"
                }
            ]
        },
        {
            "label": "Pytania tematyczne",
            "color": "amber",
            "description": "Kiedy <strong>Kto/Co jest podmiotem</strong>, kolejność słów jest taka jak w zdaniu twierdzącym (bez zrobić/does/did):",
            "examples": [
                {
                    "en": "Kto do Ciebie dzwonił?",
                    "ua": "Kto do Ciebie dzwonił? (Kto jest tematem)"
                },
                {
                    "en": "Co się stało?",
                    "ua": "Co się stało? (Jaki jest temat)"
                },
                {
                    "en": "Kto zna odpowiedź?",
                    "ua": "Kto zna odpowiedź?"
                }
            ],
            "note": "📌 Jeśli Kto/Co jest tematem, nie dodawaj „zrób/robi/zrobiłeś”!"
        }
    ]
}

{
    "title": "5. Czasowniki pomocnicze w pytaniach",
    "sections": [
        {
            "label": "DO/DOES/DID – dla czasów prostych",
            "color": "emerald",
            "description": "W czasach prostych (Present Simple, Past Simple) używamy do/does/did jako czasu pomocniczego:",
            "examples": [
                {
                    "en": "Present Simple: Do/Does",
                    "ua": "Czy ty mieszkać tutaj? Czy ona pracuje?"
                },
                {
                    "en": "Past Simple: Did",
                    "ua": "Czy oni poszli? widziałeś? jestem/jest/are"
                }
            ],
            "note": "📌 Основне дієслово у базовій формі (без -s, -ed)!"
        },
        {
            "label": "TO BE — інверсія",
            "color": "sky",
            "description": "З дієсловом <strong>to be</strong> не потрібен do/does/did — просто робимо інверсію:",
            "examples": [
                {
                    "en": "Present: am/is/are",
                    "ua": "Czy jesteś gotowy? Czy ona tu jest?"
                },
                {
                    "en": "Przeszłość: była/była",
                    "ua": "Czy on tam był? Czy byli szczęśliwi?"
                }
            ]
        },
        {
            "label": "HAVE/HAS oznacza czasy dokonane",
            "color": "purple",
            "description": "W czasach dokonanych (Present Perfect, Past Perfect) Have/has jest czasownikiem pomocniczym:",
            "examples": [
                {
                    "en": "Present Perfect: Have/has",
                    "ua": "Widziałeś to? Czy skończyła?"
                },
                {
                    "en": "past Perfect: miała Mogłaby",
                    "ua": "Had they left before you arrived?"
                }
            ]
        },
        {
            "label": "Модальні дієслова — інверсія",
            "color": "amber",
            "description": "Модальні дієслова (can, will, should, must, may, might) виносяться перед підмет:",
            "examples": [
                {
                    "en": "Can, Could",
                    "ua": "Czy możesz pomóc? Czy mogłaby przyjść?"
                },
                {
                    "en": "Will, czy",
                    "ua": "Czy przybędą? Czy chcesz herbaty?"
                },
                {
                    "en": "Powinienem, muszę, maj",
                    "ua": "Czy powinienem poczekać? Musimy iść? Czy mogę zapytać?"
                }
            ]
        }
    ]
}

{
    "title": "6. Pytania w różnych czasach",
    "sections": [
        {
            "label": "Present Simple",
            "color": "emerald",
            "description": "Używamy <strong>do/does</strong> (z to be — inwersja am/is/are):",
            "examples": [
                {
                    "en": "Czy mówisz po angielsku?",
                    "ua": "Czy mówisz Angielski?"
                },
                {
                    "en": "Czy ona tu mieszka? teraz?” Proste",
                    "ua": "Вона тут живе?"
                },
                {
                    "en": "Are you a student?",
                    "ua": "Ти студент?"
                }
            ]
        },
        {
            "label": "Present Continuous",
            "color": "sky",
            "description": "Інверсія <strong>am/is/are</strong>:",
            "examples": [
                {
                    "en": "Are you working now?",
                    "ua": "Ти зараз працюєш?"
                },
                {
                    "en": "Is she coming?",
                    "ua": "Вона йде (приходить)?"
                },
                {
                    "en": "What are they doing?",
                    "ua": "Що вони роблять?"
                }
            ]
        },
        {
            "label": "Past Simple",
            "color": "purple",
            "description": "Używamy słowa <strong>did</strong> (z być — odwrócenie was/were):",
            "examples": [
                {
                    "en": "Widziałeś film? wyszedłeś?",
                    "ua": "Ти бачив цей фільм?"
                },
                {
                    "en": "Where did she go?",
                    "ua": "Куди вона пішла?"
                },
                {
                    "en": "Byłeś w domu?",
                    "ua": "Byłeś w domu?"
                }
            ]
        },
        {
            "label": "Present Perfect",
            "color": "amber",
            "description": "Inwersja <strong>mieć/ma</strong>:",
            "examples": [
                {
                    "en": "Byłeś kiedyś w Paryżu?",
                    "ua": "Byłeś kiedyś w Paryżu?"
                },
                {
                    "en": "Czy ona ją skończyła działa?",
                    "ua": " Co oni zrobili? "
                },
                {
                    "en": "Co oni zrobili? Impreza? Porównanie typów pytań",
                    "ua": "Що вони зробили?"
                }
            ]
        },
        {
            "label": "Future Simple",
            "color": "rose",
            "description": "Інверсія <strong>will</strong>:",
            "examples": [
                {
                    "en": "Will you come to the party?",
                    "ua": "Ти прийдеш на вечірку?"
                },
                {
                    "en": "When will she arrive?",
                    "ua": "Коли вона приїде?"
                },
                {
                    "en": "What will they do?",
                    "ua": "Що вони робитимуть?"
                }
            ]
        }
    ]
}

{
    "title": "7. Порівняння типів питань",
    "intro": "Różne rodzaje zdań pytających w języku angielskim:",
    "rows": [
        {
            "en": "Pytania tak/nie",
            "ua": "Pytania ogólne",
            "note": "Czy lubisz herbatę? — Tak/Nie"
        },
        {
            "en": "Jakie pytania",
            "ua": "Pytania specjalne",
            "note": "Czego chcesz? — Informacje szczegółowe"
        },
        {
            "en": "Pytania tematyczne",
            "ua": "Pytania tematyczne",
            "note": "Kto dzwonił? — Nie ma potrzeby robienia/robienia"
        },
        {
            "en": "Pytania alternatywne",
            "ua": "Pytania alternatywne",
            "note": "Herbata czy kawa? — Wybór pomiędzy opcjami"
        },
        {
            "en": "Otaguj pytania",
            "ua": "Pytania sekcyjne",
            "note": "Podoba Ci się, prawda? — Potwierdzenie"
        },
        {
            "en": "Pytania pośrednie",
            "ua": "Pytania pośrednie",
            "note": "Czy możesz mi powiedzieć gdzie…? — Bardziej grzecznie"
        }
    ],
    "warning": "📌 Każdy typ pytania ma swoją własną, specyficzną strukturę!"
}

{
    "title": "8. Kiedy używać do/does/did",
    "intro": "Zasady używania czasowników posiłkowych do/does/did:",
    "rows": [
        {
            "en": "Czasy proste (czasowniki główne)",
            "ua": "Z czasownikami głównymi",
            "note": "Czy pracujesz? Czy ona wie? Czy poszli?"
        },
        {
            "en": "NIE z TO BE",
            "ua": "NIE z TO BE",
            "note": "]❌ Czy jesteś szczęśliwy? ✅ Czy jesteś zadowolony?"
        },
        {
            "en": "NIE z modami",
            "ua": "NIE z modami",
            "note": "❌ Czy potrafisz pływać? ✅ Umiesz pływać?"
        },
        {
            "en": "NIE z mieć (idealnie)",
            "ua": "NIE z mieć (idealnie)",
            "note": "❌ Widziałeś? ✅ Widziałeś?"
        },
        {
            "en": "NIE w pytaniach tematycznych",
            "ua": "NIE w pytaniach tematycznych",
            "note": "❌ Kto dzwonił? ✅ Kto dzwonił?"
        }
    ],
    "warning": "⚠️ Do/Does/Did używa się TYLKO z czasownikami głównymi w czasach prostych!"
}

{
    "title": "9. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Nieprawidłowa kolejność słów – podmiot przed czasownikiem posiłkowym.",
            "wrong": "❌ Jesteś szczęśliwy? Umie pływać?",
            "right": " ✅ <span class="font-mono">Czy jesteś szczęśliwy? Czy potrafi pływać?</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Używanie funkcji „zrób/zrób” z „być”.",
            "wrong": "❌ Czy jesteś gotowy? Byłeś tam?",
            "right": "​​​​​​ Byłeś tam?</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Użycie do/does/did z czasownikami modalnymi.",
            "wrong": "❌ Czy możesz pomóc? Czy ona przyszła? ",
            "right": " ✅ <span class="font-mono">Czy możesz pomóc? Czy mogłaby przyjść?</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Niepoprawna forma głównego czasownika.",
            "wrong": "❌ Czy ona pracuje? Czy poszli?",
            "right": " ✅ <span class="font-mono">Czy ona działa? Czy poszli?</span>"
        },
        {
            "label": "Błąd 5",
            "color": "emerald",
            "title": "Dodawanie „co/robi” w pytaniach do tematu.",
            "wrong": "❌ Kto do ciebie dzwonił? Co się stało?",
            "right": "​​​​ <span class="font-mono">Kto do ciebie dzwonił? Co się stało?</span>"
        },
        {
            "label": "Błąd 6",
            "color": "indigo",
            "title": "Pominięcie czasownika posiłkowego.",
            "wrong": "❌ Lubisz kawę? Ona mówi po angielsku?",
            "right": "​​​​ <span class="font-mono">Czy lubisz kawę? Czy ona mówi po angielsku?</span>"
        }
    ]
}

{
    "title": "11. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwą opcję",
    "select_intro": "Wybierz poprawną formę pytania.",
    "selects": [
        {
            "label": "a) Czy jesteś szczęśliwy? / b) Czy jesteś szczęśliwy? /c) Czy jesteś szczęśliwy?",
            "prompt": "Która opcja jest prawidłowa?"
        },
        {
            "label": "a) Gdzie ona mieszka? / b) Gdzie ona mieszka? / c) Gdzie ona mieszka?",
            "prompt": "Która opcja jest prawidłowa?"
        },
        {
            "label": "a) Czy możesz mi pomóc? / b) Czy możesz mi pomóc? / c) Możesz mi pomóc?",
            "prompt": "Która opcja jest prawidłowa?"
        },
        {
            "label": "a) Kto dzwonił? / b) Kto dzwonił? / c) Kto dzwoni? Francuski. → ",
            "prompt": "Який варіант правильний?"
        }
    ],
    "options": [
        "a",
        "b",
        "c"
    ],
    "input_title": "Вправа 2. Постав питання",
    "input_intro": "Утвори питання з поданого речення.",
    "inputs": [
        {
            "before": "She speaks French. → ",
            "after": ""
        },
        {
            "before": "Oni są studentami. → ",
            "after": ""
        },
        {
            "before": "Umie prowadzić. → ",
            "after": ""
        },
        {
            "before": "Pojechałeś do Paryża. (Gdzie...?) → ",
            "after": ""
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd w pytaniu.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Jesteś gotowy?",
            "example_target": "Czy jesteś gotowy? gotowy?"
        },
        {
            "original": "1. Czy jesteś zadowolony?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Gdzie ona mieszka?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "3. Czy umiesz pływać?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "4. Kto do Ciebie dzwonił?",
            "placeholder": "Poprawka"
        }
    ]
}

{
    "title": "Inne tematy z sekcji Zdania pytające i zastrzeżenia",
    "items": [
        {
            "label": "Formularze pytań – Jak zadawać pytania (bieżące)",
            "current": true
        },
        {
            "label": "Pytania tak/nie – Ogólne pytania",
            "current": false
        },
        {
            "label": "Wh-Pytania – pytania specjalne",
            "current": false
        },
        {
            "label": "Tagi pytań – pytania przekrojowe",
            "current": false
        },
        {
            "label": "Krótkie odpowiedzi – krótkie odpowiedzi",
            "current": false
        }
    ]
}
